import axios from 'axios';
import { API_ENDPOINTS } from '../constants';

// Create axios instances with proper configuration
const createApiInstance = (baseURL) => {
  const instance = axios.create({
    baseURL,
    timeout: 10000, // 10 seconds timeout
    headers: {
      'Content-Type': 'application/json',
    },
  });

  // Request interceptor to add auth token
  instance.interceptors.request.use(
    (config) => {
      const token = localStorage.getItem('authToken');
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
      return config;
    },
    (error) => {
      return Promise.reject(error);
    }
  );

  // Response interceptor for error handling
  instance.interceptors.response.use(
    (response) => response,
    (error) => {
      if (error.response?.status === 401) {
        // Token expired or invalid
        localStorage.removeItem('authToken');
        localStorage.removeItem('userData');
        window.location.href = '/login';
      }
      return Promise.reject(error);
    }
  );

  return instance;
};

// API instances
export const userAPI = createApiInstance(API_ENDPOINTS.USER);
export const inventoryAPI = createApiInstance(API_ENDPOINTS.INVENTORY);
export const orderAPI = createApiInstance(API_ENDPOINTS.ORDER);

// API service functions
export const apiService = {
  // User API
  login: (credentials) => userAPI.post('/auth/login', credentials),
  signup: (userData) => userAPI.post('/auth/signup', userData),
  getProfile: () => userAPI.get('/auth/profile'),
  updateProfile: (data) => userAPI.put('/auth/profile', data),

  // Inventory API
  getProducts: (params) => inventoryAPI.get('/products', { params }),
  getProduct: (id) => inventoryAPI.get(`/products/${id}`),
  addProduct: (product) => inventoryAPI.post('/products', product),
  updateProduct: (id, product) => inventoryAPI.put(`/products/${id}`, product),
  deleteProduct: (id) => inventoryAPI.delete(`/products/${id}`),

  // Order API
  getOrders: (params) => orderAPI.get('/orders', { params }),
  getOrder: (id) => orderAPI.get(`/orders/${id}`),
  createOrder: (order) => orderAPI.post('/orders', order),
  updateOrderStatus: (id, status) => orderAPI.put(`/orders/${id}/status`, { status }),
  cancelOrder: (id) => orderAPI.put(`/orders/${id}/cancel`),
};